<template>
  <div>
    <section id="start-section" class="site-section">
      <div class="container text-container">
        <div class="start-heading">Hi, I’m Jonathan!</div>
        <p>I’m a software developer based in Düsseldorf, Germany. Currently, I work for Riege Software GmbH.</p>
      </div>
      <div class="container image-container">
        <div class="floating-hand-image-content" :style="{height: handImageWidth + 'px'}">
          <img v-for="(image, i) in minImages" class="min-image" :key="i" :src="image.src" :alt="image.alt"
               :style="getMinItemPosition(i)">
          <img class="hand-image" src="../assets/images/hand.png" alt="Hand Image">
        </div>
      </div>
    </section>
    <div class="first-between betweener"></div>
  </div>
</template>

<script>
export default {
  name: "StartSection",
  created() {
    setInterval(() => {
      this.repositionItems();
    }, 100)
  },
  data: () => {
    return {
      seconds: 0,
      handImageWidth: 0,
      minImages: [
        {
          src: require("@/assets/images/java_min.png"),
          alt: "Mini Java Icon"
        },
        {
          src: require("@/assets/images/window_min.png"),
          alt: "Mini Window Icon"
        },
        {
          src: require("../assets/images/js_min.png"),
          alt: "Mini Maths Icon"
        },
        {
          src: require("../assets/images/brackets_min.png"),
          alt: "Mini Programming Icon"
        },
        {
          src: require("../assets/images/mertens_min.png"),
          alt: "Mini Mertens Sum Icon"
        }]
    }

  },
  methods: {
    getMinItemPosition(index) {
      return {
        left: (0.5 + Math.sin(this.seconds + 10 * index) * 0.4) * this.handImageWidth + "px",
        top: (0.5 + Math.sin(-this.seconds + 20 * index) * 0.4) * this.handImageWidth + "px",
        zIndex: -2 * Math.floor(Math.cos(this.seconds + 10 * index))
      }
    },
    repositionItems() {
      this.seconds = new Date().getTime() / 1000;
      this.handImageWidth = document.querySelector(".floating-hand-image-content").clientWidth;
    }
  }
}
</script>

